Bash(node -e "
const { createClient } = require\('@supabase/supabase-js'\);
require\('dotenv'\).config\({ path: '.env.local' }\);
const sb = createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY\);
\(async \(\) => {
  const { data: spaces } = await sb.from\('Space'\).select\('id, name'\).order\('name'\);
  const { data: members } = await sb.from\('SpaceMember'\).select\('spaceId, userId, role'\);
  const { data: users } = await sb.from\('User'\).select\('id, name, role'\);
  const userMap = new Map\(users.map\(u => [u.id, u]\)\);

  let total = 0;
  for \(const s of spaces\) {
    const sm = members.filter\(m => m.spaceId === s.id\);
    const admins = sm.filter\(m => m.role === 'ADMIN'\).length;
    const mems = sm.filter\(m => m.role === 'MEMBER'\).length;
    total += sm.length;
    console.log\(s.name.padEnd\(30\) + String\(sm.length\).padStart\(3\) + '  \(ADMIN:' + String\(admins\).padStart\(2\) + ', MEMBER:' + String\(mems\).padStart\(2\) + '\)'\);
  }
  console.log\('─'.repeat\(55\)\);
  console.log\('Total SpaceMembers:'.padEnd\(30\) + String\(total\).padStart\(3\)\);

  // Verify no ADMIN/SUPER_ADMIN users have SpaceMembers
  const adminInSM = members.filter\(m => { const u = userMap.get\(m.userId\); return u && \(u.role === 'ADMIN' || u.role === 'SUPER_ADMIN'\); }\);
  console.log\('ADMIN/SUPER_ADMIN en SpaceMember: ' + adminInSM.length + \(adminInSM.length === 0 ? ' ✅' : ' ❌'\)\);
}\)\(\);
" 2>&1)

