Bash(node -e "
const { createClient } = require\('@supabase/supabase-js'\);
require\('dotenv'\).config\({ path: '.env.local' }\);
const sb = createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY\);
\(async \(\) => {
  // Check if RLS is enabled on Space
  const { data: rlsCheck, error: rlsErr } = await sb.rpc\('to_regclass', { arg: 'Space' }\).maybeSingle\(\);

  // Try executing the SQL directly
  const sql = \\`
    DROP POLICY IF EXISTS \\"space_select\\" ON \\"Space\\";
    CREATE POLICY \\"space_select\\" ON \\"Space\\"
      FOR SELECT USING \(
        EXISTS \(
          SELECT 1 FROM \\"User\\"
          WHERE id = auth.uid\(\)::text
          AND role IN \('ADMIN', 'SUPER_ADMIN'\)
        \)
        OR
        EXISTS \(
          SELECT 1 FROM \\"SpaceMember\\"
          WHERE \\"spaceId\\" = \\"Space\\".id
          AND \\"userId\\" = auth.uid\(\)::text
        \)
      \);
  \\`;

  const { data, error } = await sb.rpc\('exec_sql', { sql_query: sql }\);
  if \(error\) {
    console.log\('RPC exec_sql not available:', error.message\);
    console.log\('Trying direct query...'\);

    // Check existing policies
    const { data: policies, error: pErr } = await sb
      .from\('pg_policies'\)
      .select\('*'\)
      .eq\('tablename', 'Space'\);

    if \(pErr\) {
      console.log\('Cannot query pg_policies:', pErr.message\);
    } else {
      console.log\('Existing policies on Space:', JSON.stringify\(policies, null, 2\)\);
    }

    // Check if RLS is enabled
    const { data: rlsData, error: rlsError } = await sb.rpc\('check_rls', { table_name: 'Space' }\);
    if \(rlsError\) console.log\('Cannot check RLS:', rlsError.message\);
    else console.log\('RLS status:', rlsData\);
  } else {
    console.log\('SQL executed successfully'\);
  }
}\)\(\);
" 2>&1)

